1	// Quote constants
2	const PROCESSING_FEE = 5;
3	const DEFAULT_BASE_PREMIUM = 100;
4	const CURSE_SURCHARGE_RATE = 0.5;
5	const FIRST_INSURANCE_RATE = 0.1;
6	const HIGH_ENCHANTMENT_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const LOYALTY_DISCOUNT_RATE = 0.2;
9	const LOYALTY_THRESHOLD_YEARS = 2;
10	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
11	
12	// Claim constants
13	const DEDUCTIBLE = 100;
14	const CAP_MULTIPLIER = 2;
15	const DEFAULT_INSURANCE_VALUE = 1000;
16	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
17	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
18	const FULL_PAYOUT_RATE = 1;
19	
20	type QuoteItem = { type: string; material?: string; enchantment?: number; cursed?: boolean };
21	type Damage = { itemType: string; amount: number };
22	type Incident = { cause: string; damages: Damage[] };
23	type Step =
24	  | { op: "quote"; items: QuoteItem[] }
25	  | { op: "claim"; policy: number; incident: Incident };
26	type Customer = { yearsWithMHPCO: number };
27	type Scenario = { customer: Customer; steps: Step[] };
28	
29	const BLOCK_TYPE = "block";
30	const BLOCK_OF_THREE_BASE = 60;
31	const BLOCK_SIZE = 3;
32	
33	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
34	  amulet: 60,
35	  rune: 25,
36	  moonstone: 25,
37	  [BLOCK_TYPE]: BLOCK_OF_THREE_BASE,
38	};
39	const BLOCK_TYPES = new Set(["rune", "moonstone"]);
40	
41	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
42	  sword: 1000,
43	  amulet: 600,
44	  staff: 800,
45	  potion: 400,
46	  rune: 250,
47	  moonstone: 250,
48	};
49	
50	const insuranceValueForItem = (item: QuoteItem): number =>
51	  INSURANCE_VALUE_BY_TYPE[item.type] ?? DEFAULT_INSURANCE_VALUE;
52	
53	const basePremiumForItem = (item: QuoteItem): number =>
54	  BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;
55	
56	const groupByType = (items: QuoteItem[]): Map<string, QuoteItem[]> =>
57	  items.reduce((groups, item) => {
58	    const group = groups.get(item.type) ?? [];
59	    return groups.set(item.type, [...group, item]);
60	  }, new Map<string, QuoteItem[]>());
61	
62	const isHighEnchantment = (item: QuoteItem): boolean =>
63	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
64	
65	const itemSurchargeRate = (item: QuoteItem): number =>
66	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
67	  (isHighEnchantment(item) ? HIGH_ENCHANTMENT_RATE : 0) +
68	  FIRST_INSURANCE_RATE;
69	
70	const itemPremium = (item: QuoteItem): number => {
71	  const base = basePremiumForItem(item);
72	  return base + base * itemSurchargeRate(item);
73	};
74	
75	const isBlockGroup = (type: string, group: QuoteItem[]): boolean =>
76	  BLOCK_TYPES.has(type) && group.length === BLOCK_SIZE;
77	
78	const billingItems = (items: QuoteItem[]): QuoteItem[] =>
79	  [...groupByType(items)].flatMap(([type, group]) =>
80	    isBlockGroup(type, group) ? [{ type: BLOCK_TYPE }] : group,
81	  );
82	
83	const sumBy = <T>(items: T[], fn: (item: T) => number): number =>
84	  items.reduce((total, item) => total + fn(item), 0);
85	
86	const policyDiscountRate = (customer: Customer, quoteIndex: number): number =>
87	  (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE : 0) +
88	  (quoteIndex > 0 ? FOLLOW_UP_DISCOUNT_RATE : 0);
89	
90	type QuoteResult = { premium: number };
91	type ClaimResult = { payout: number; remainingCap: number };
92	type StepResult = QuoteResult | ClaimResult;
93	
94	type Policy = { items: QuoteItem[]; remainingCap: number };
95	
96	const quoteStep = (
97	  customer: Customer,
98	  quoteIndex: number,
99	  items: QuoteItem[],
100	): QuoteResult => {
101	  const billables = billingItems(items);
102	  const policyBase = sumBy(billables, basePremiumForItem);
103	  const subtotal = sumBy(billables, itemPremium);
104	  const discount = policyBase * policyDiscountRate(customer, quoteIndex);
105	  return { premium: Math.ceil(subtotal - discount + PROCESSING_FEE) };
106	};
107	
108	const payoutRate = (item: QuoteItem | undefined): number =>
109	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
110	    ? HIGH_ENCHANTMENT_PAYOUT_RATE
111	    : FULL_PAYOUT_RATE;
112	
113	const findInsuredItem = (policy: Policy, itemType: string): QuoteItem | undefined =>
114	  policy.items.find((it) => it.type === itemType);
115	
116	const damagePayout = (policy: Policy, dmg: Damage): number =>
117	  dmg.amount * payoutRate(findInsuredItem(policy, dmg.itemType)) - DEDUCTIBLE;
118	
119	const claimStep = (policy: Policy, incident: Incident): { result: ClaimResult; policy: Policy } => {
120	  const desiredPayout = sumBy(incident.damages, (dmg) => damagePayout(policy, dmg));
121	  const payout = Math.min(desiredPayout, policy.remainingCap);
122	  const remainingCap = policy.remainingCap - payout;
123	  return {
124	    result: { payout, remainingCap },
125	    policy: { ...policy, remainingCap },
126	  };
127	};
128	
129	const policyFromItems = (items: QuoteItem[]): Policy => ({
130	  items,
131	  remainingCap: sumBy(items, insuranceValueForItem) * CAP_MULTIPLIER,
132	});
133	
134	type ScenarioState = {
135	  results: StepResult[];
136	  quoteIndex: number;
137	  policies: Record<number, Policy>;
138	};
139	
140	const initialState: ScenarioState = { results: [], quoteIndex: 0, policies: {} };
141	
142	const applyQuote = (
143	  customer: Customer,
144	  state: ScenarioState,
145	  items: QuoteItem[],
146	  policyId: number,
147	): ScenarioState => ({
148	  ...state,
149	  results: [...state.results, quoteStep(customer, state.quoteIndex, items)],
150	  quoteIndex: state.quoteIndex + 1,
151	  policies: { ...state.policies, [policyId]: policyFromItems(items) },
152	});
153	
154	const applyClaim = (
155	  state: ScenarioState,
156	  policyId: number,
157	  incident: Incident,
158	): ScenarioState => {
159	  const { result, policy } = claimStep(state.policies[policyId], incident);
160	  return {
161	    ...state,
162	    results: [...state.results, result],
163	    policies: { ...state.policies, [policyId]: policy },
164	  };
165	};
166	
167	const applyStep = (
168	  customer: Customer,
169	  state: ScenarioState,
170	  step: Step,
171	  index: number,
172	): ScenarioState =>
173	  step.op === "quote"
174	    ? applyQuote(customer, state, step.items, index)
175	    : applyClaim(state, step.policy, step.incident);
176	
177	export const runScenario = (scenario: unknown): unknown => {
178	  const { customer, steps } = scenario as Scenario;
179	  const { results } = steps.reduce(
180	    (state, step, index) => applyStep(customer, state, step, index),
181	    initialState,
182	  );
183	  return { results };
184	};
